function findUser(a, c){
const {MongoClient} = require("mongodb");
const uri = "mongodb://amruthn1:Nad05473@cluster0-shard-00-00.3lwao.mongodb.net:27017,cluster0-shard-00-01.3lwao.mongodb.net:27017,cluster0-shard-00-02.3lwao.mongodb.net:27017/names?ssl=true&replicaSet=atlas-tsxz56-shard-0&authSource=admin&retryWrites=true&w=majority";
const client = new MongoClient(uri);
async function run() {
    try {
        await client.connect();
        const database = client.db('name_collection');
        const collection = database.collection('names');
        const query = {
            user: a,
            password: c
        };
        const name = await collection.findOne(query);
        if (name === null){
            let data = {
                message: name
            }
            let f = JSON.stringify(data);
            fs.writeFileSync('data/temp.json', f)
            h(); 
        } else {
            let data = {
                message: name
            }
            delete data.message.user
            delete data.message.password
            let f = JSON.stringify(data);
            fs.writeFileSync('data/temp.json', f)
            h(); 
        }
        function h(){
            let rawdata = fs.readFileSync('data/temp.json')
        }
    } finally {
        await client.close();
    }
}
run().catch(console.dir)
}
